import { Component, Event, EventEmitter, h, Host, Prop, State } from '@stencil/core';
import { getNewUuid } from '@src/utils/mx-utils/item-uuids';

@Component({
  tag: 'mx-paragraph-accordion',
  styleUrl: 'mx-paragraph-accordion.css'
})
export class MxParagraphAccordion {

  /** Sets if the paragraph accordion is open by default. */
  @Prop() readonly defaultOpen: boolean = false;

  /** Sets class name of paragraph tag */
  @Prop() readonly paragraphClass: string;

  /** Sets the content of the paragraph tag */
  @Prop() readonly text: string;

  /** Sets the width of the div (default 100%) */
  @Prop() readonly width: string = '100%';

  /** Sets the expanded link text */
  @Prop() readonly expandLinkText: string = 'Show More';

  /** Sets the collapse link text */
  @Prop() readonly collapseLinkText: string = 'Show Less';

  /** Sets weather the collapse link shows */
  @Prop() readonly showCollapseLink: boolean = true;

  /** Sets uniq id for each item's */
  @Prop() readonly uniqueId = getNewUuid();

  /** Emits event with opened state. */
  @Event() accordionToggled: EventEmitter<boolean>;

  @State() open = this.defaultOpen;

  private paragraphAccordionWrapperRef: HTMLDivElement;
  private paragraphAccordionRef: HTMLParagraphElement;
  private readonly numberOfLines = 2;

  componentDidLoad() {
    this.setContainerHeight();
  }

  private readonly handleClick = (event: MouseEvent) => {
    this.open = !this.open;
    event.stopPropagation();
    this.setContainerHeight();
    this.accordionToggled.emit(this.open);
  };

  private readonly wrapperRefHeight = () => {
    if (this.open) {
      return this.paragraphAccordionWrapperRef.scrollHeight;
    } else {
      const lineHeight = parseFloat(window.getComputedStyle(this.paragraphAccordionRef).lineHeight);
      return (lineHeight * this.numberOfLines) + 10;
    }
  };

  private readonly setContainerHeight = () => {
    this.paragraphAccordionWrapperRef.style.height = `${this.wrapperRefHeight()}px`;
    this.paragraphAccordionWrapperRef.style.paddingTop = '10px';
  };

  render() {
    return (
      <Host style={{ width: this.width }}
        class='inline-block'>
        <section>
          <div ref={(ref) => this.paragraphAccordionWrapperRef = ref}
            class={{
              'body-m mb-8 preview-text': true,
              'mx-paragraph-accordion-wrapper': true,
              'preview-text-open': this.open,
              'preview-text-closed': !this.open
            }}>
            <p ref={(ref) => this.paragraphAccordionRef = ref}
              id={this.uniqueId}
              class={{
                'text-primary': true,
                [this.paragraphClass]: !!this.paragraphClass
              }}>
              {this.text}
            </p>
          </div>
          <kds-link class={{ 'mx-paragraph-action-link': true, hidden: this.open && !this.showCollapseLink }}
            inner-aria-expanded={this.open ? 'true' : 'false'}
            inner-aria-controls={this.uniqueId}
            onClick={this.handleClick}>
            {this.open ? this.collapseLinkText : this.expandLinkText}
          </kds-link>
        </section>
      </Host>
    );
  }

}
